// Import of required libraries
import { test } from '@playwright/test';
import { expect, getValue, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(603000);
    const errors: Error[] = [];
    page.on('pageerror', (err) => errors.push(err));

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    await page.goto("http://localhost:8055/admin/login");
    await page.waitForLoadState('networkidle');

    const playwrightRequest2: Record<string, any> = {
        "email": "admin@example.com",
        "password": "admin"
    };

    await page.getByRole("textbox", { name: "Email" }).fill(getValue(playwrightRequest2, "email"));
    await page.getByRole("textbox", { name: "Password" }).fill(getValue(playwrightRequest2, "password"));
    const responsePromise2 = page.waitForResponse("**/auth/login**");
    await page.getByRole("button", { name: "Sign In" }).click();
    const response2 = await responsePromise2;
    expect(response2.status()).toBe(200);

    await page.waitForLoadState('networkidle');

    await page.goto("http://localhost:8055/admin/content/articles");
    await page.waitForLoadState('networkidle');
    // Wait for items to load
    await page.waitForTimeout(3000);

    await expect(page.getByTestId("root").getByText("Items")).toContainText("5 Items");
    await expect(page.getByRole("row")).toHaveCount(6);
    await page.getByRole("button", { name: "search" }).click();
    await page.getByRole("searchbox", { name: "Search Items..." }).fill("Article 3");
    // Wait for network activities to finish
    await page.waitForTimeout(3000);

    await expect(page.getByTestId("root").getByText("Item")).toContainText("One Item");
    await expect(page.getByRole("row")).toHaveCount(2);
    await expect(page.getByRole("cell", { name: "Article 3 - Test Content" })).toContainText("Article 3 - Test Content");
    await page.getByRole("button", { exact: true, name: "close" }).click();
    // Wait for network activities to finish
    await page.waitForTimeout(3000);

    await expect(page.getByTestId("root").getByText("Items")).toContainText("5 Items");
    await page.getByRole("button", { name: "Title arrow_drop_down" }).click();
    await page.getByRole("button", { name: "sort Sort Ascending" }).click();
    // Wait for network activities to finish
    await page.waitForTimeout(3000);

    await page.goto("http://localhost:8055/admin/content/articles?search=Article+5");
    // Wait for network activities to finish
    await page.waitForTimeout(3000);

    await expect(page.getByRole("searchbox", { name: "Search Items..." })).toHaveValue("Article 5");
    await expect(page.getByTestId("root").getByText("Item")).toContainText("One Item");
    await expect(page.getByRole("cell", { name: "Article 5 - Test Content" })).toContainText("Article 5 - Test Content");
    expect(errors).toHaveLength(0);
});
